require("Game.Amulet.SciNum")Amulet_String={}function Amulet_String.get_sign_and_abs(a)if a:sub(1,1)=='-'then return-1,a:sub(2)else return 1,a end end;function Amulet_String.compare_abs(b,c)b=tostring(b)c=tostring(c)local d=SciNum.new(b)local e=SciNum.new(c)local f=d:compare(e)return f end;function Amulet_String.add(b,c)b=tostring(b)c=tostring(c)local d=SciNum.new(b)local e=SciNum.new(c)local g=d:add(e)return g:tostring()or'0'end;function Amulet_String.subtract(b,c)b=tostring(b)c=tostring(c)local d=SciNum.new(b)local e=SciNum.new(c)local h=d:subtract(e)return h:tostring()or'0'end;function Amulet_String.multiply(b,c,i)b=tostring(b)c=tostring(c)local d=SciNum.new(b)local e=SciNum.new(c)local j=d:multiply(e)return j:tostring()or'0',j end;function Amulet_String.multiply_three(b,c,k)local l=Amulet_String.multiply(b,c)local m=Amulet_String.multiply(l,k)return m end;function Amulet_String.floor(a)a=tostring(a)return string.format("%.0f",a)end;function Amulet_String.multiply_abs(b,c)local n=#b;local o=#c;local p={}for q=n,1,-1 do local r=tonumber(b:sub(q,q))local s=0;local t={}for u=o,1,-1 do local v=tonumber(c:sub(u,u))local j=r*v+s;s=math.floor(j/10)table.insert(t,1,tostring(j%10))end;if s>0 then table.insert(t,1,tostring(s))end;for w=1,n-q do table.insert(t,'0')end;p=Amulet_String.add_table(p,t)end;return table.concat(p)end;function Amulet_String.add_table(x,y)local p={}local s=0;local q=#x;local u=#y;while q>0 or u>0 or s>0 do local r=q>0 and tonumber(x[q])or 0;local v=u>0 and tonumber(y[u])or 0;local g=r+v+s;s=math.floor(g/10)table.insert(p,1,tostring(g%10))q=q-1;u=u-1 end;return p end;function Amulet_String.divide(b,c)b=tostring(b)c=tostring(c)local d=SciNum.new(b)local e=SciNum.new(c)local z=d:divide(e)return z:tostring()end;function Amulet_String.divideAmuletFerver(b,c)b=tostring(b)c=tostring(c)local d=SciNum.new(b)local e=SciNum.new(c)local z=d:divide(e)local A,B=z:toPercentage()return A*0.01 end;return Amulet_String